def gen(rng, size):
    alpha = 'abcde'
    def word():
        ln = rng.randint(1, 10)
        return ''.join(rng.choice(alpha) for _ in range(ln))
    seen = set()
    w1 = []
    while len(w1) < max(1, size):
        w = word()
        if w not in seen:
            seen.add(w)
            w1.append(w)
    w2 = [word() for _ in range(rng.randint(1, 6))]
    return [w1, w2]

