class Solution:
    def wordSubsets(self, words1, words2):
        from collections import Counter
        res = []
        reqs = [Counter(b) for b in words2]
        for a in words1:
            ca = Counter(a)
            ok = True
            for r in reqs:
                for ch, k in r.items():
                    if ca[ch] < k:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                res.append(a)
        return res

