class Solution:
    def wordSubsets(self, words1, words2):
        from collections import Counter
        need = Counter()
        for b in words2:
            cb = Counter(b)
            for ch, k in cb.items():
                if k > need[ch]:
                    need[ch] = k
        res = []
        for a in words1:
            ca = Counter(a)
            if all(ca[ch] >= k for ch, k in need.items()):
                res.append(a)
        return res

