var wordSubsets = function(words1, words2) {
    const need = new Array(26).fill(0);
    const cnt = (w) => {
        const c = new Array(26).fill(0);
        for (const ch of w) c[ch.charCodeAt(0) - 97]++;
        return c;
    };
    for (const b of words2) {
        const cb = cnt(b);
        for (let i = 0; i < 26; i++) if (cb[i] > need[i]) need[i] = cb[i];
    }
    const res = [];
    for (const a of words1) {
        const ca = cnt(a);
        let ok = true;
        for (let i = 0; i < 26; i++) if (ca[i] < need[i]) { ok = false; break; }
        if (ok) res.push(a);
    }
    return res;
};
